cells.source:
/* Parametrise the hemisphere */
r_s: [R*sin(th)*cos(ph), R*sin(th)*sin(ph), R*cos(th)]$

/* Tangent vectors */
r_th: diff(r_s, th)$
r_ph: diff(r_s, ph)$

/* Normal vector: r_th × r_ph (outward for upper hemisphere) */
normal: trigsimp([r_th[2]*r_ph[3] - r_th[3]*r_ph[2],
                  r_th[3]*r_ph[1] - r_th[1]*r_ph[3],
                  r_th[1]*r_ph[2] - r_th[2]*r_ph[1]])

/* Parametrise the boundary circle */
r_t: [R*cos(t), R*sin(t), 0]$
dr_t: diff(r_t, t)$

/* u evaluated on the curve */
u_on_C: subst([x = R*cos(t), y = R*sin(t), z = 0], u)$

/* Integrand: u · r'(t) */
line_integrand: trigsimp(u_on_C[1]*dr_t[1] + u_on_C[2]*dr_t[2] + u_on_C[3]*dr_t[3])
